const parts = [$.input.marketFocus];
const staticTerms = "today stock market summary news major moves";
return { query: parts.filter(Boolean).join(" ") + " " + staticTerms };

const market = $.steps.searchMarketNews.response.results || [];
const sector = $.steps.searchSectorNews.response.results || [];

let sourcesText = 'MARKET NEWS:\n';
market.forEach((r, i) => {
  sourcesText += (i + 1) + '. ' + (r.title || 'Untitled') + '\n';
  sourcesText += '   URL: ' + r.url + '\n';
  if (r.publishedDate) sourcesText += '   Published: ' + r.publishedDate + '\n';
  sourcesText += '   ' + (r.text || '').slice(0, 1200) + '\n\n';
});

sourcesText += '\nSECTOR NEWS:\n';
sector.forEach((r, i) => {
  sourcesText += (market.length + i + 1) + '. ' + (r.title || 'Untitled') + '\n';
  sourcesText += '   URL: ' + r.url + '\n';
  sourcesText += '   ' + (r.text || '').slice(0, 1000) + '\n\n';
});

return { sourcesText, totalSources: market.length + sector.length };

const d = $.steps.compileSources.output;
const focus = $.input.marketFocus || 'US stock market';
const sectors = $.input.sectors || 'technology, healthcare, finance, energy, consumer';
const today = new Date().toISOString().slice(0, 10);

let prompt = 'You are a financial market analyst. Create a comprehensive daily market summary.\n\n';
prompt += 'MARKET FOCUS: ' + focus + '\n';
prompt += 'SECTORS TO TRACK: ' + sectors + '\n';
prompt += 'DATE: ' + today + '\n\n';
prompt += 'NEWS SOURCES (' + d.totalSources + ' articles):\n';
prompt += d.sourcesText + '\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Summarize overall market direction and sentiment\n';
prompt += '- Report major index movements (S&P 500, NASDAQ, Dow Jones)\n';
prompt += '- Highlight top movers (gainers and losers)\n';
prompt += '- Sector performance breakdown\n';
prompt += '- Key catalysts and events driving the market\n';
prompt += '- Upcoming events to watch\n';
prompt += '- Use Slack mrkdwn: *bold*, _italic_. No markdown tables. No # headings.\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "date": "' + today + '",\n';
prompt += '  "marketSentiment": "bullish|bearish|neutral|mixed",\n';
prompt += '  "indices": {\n';
prompt += '    "sp500": { "value": "", "change": "", "percentChange": "" },\n';
prompt += '    "nasdaq": { "value": "", "change": "", "percentChange": "" },\n';
prompt += '    "dowJones": { "value": "", "change": "", "percentChange": "" }\n';
prompt += '  },\n';
prompt += '  "topGainers": [{ "name": "", "change": "" }],\n';
prompt += '  "topLosers": [{ "name": "", "change": "" }],\n';
prompt += '  "sectorPerformance": [{ "sector": "", "performance": "", "outlook": "" }],\n';
prompt += '  "keyCatalysts": ["catalyst 1", "catalyst 2"],\n';
prompt += '  "upcomingEvents": ["event 1", "event 2"],\n';
prompt += '  "executiveSummary": "2-3 sentence market overview",\n';
prompt += '  "tradingOutlook": "brief outlook for next session"\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiSummary.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { date: new Date().toISOString().slice(0, 10), marketSentiment: 'unknown', indices: {}, topGainers: [], topLosers: [], sectorPerformance: [], keyCatalysts: [], upcomingEvents: [], executiveSummary: raw, tradingOutlook: '' }; }

const ai = $.steps.parseAI.output;
const date = ai.date || new Date().toISOString().slice(0, 10);

const sentimentEmoji = { bullish: ':chart_with_upwards_trend:', bearish: ':chart_with_downwards_trend:', neutral: ':left_right_arrow:', mixed: ':twisted_rightwards_arrows:' };
const emoji = sentimentEmoji[ai.marketSentiment] || ':bar_chart:';

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Daily Market Summary - ' + date } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: emoji + ' *Market Sentiment:* ' + (ai.marketSentiment || 'unknown').toUpperCase() } });
blocks.push({ type: 'divider' });

blocks.push({ type: 'section', text: { type: 'mrkdwn', text: (ai.executiveSummary || 'No summary available').slice(0, 2900) } });
blocks.push({ type: 'divider' });

const indices = ai.indices || {};
let indexText = '*Major Indices:*\n';
if (indices.sp500) indexText += ':chart_with_upwards_trend: *S&P 500:* ' + (indices.sp500.value || 'N/A') + ' (' + (indices.sp500.percentChange || 'N/A') + ')\n';
if (indices.nasdaq) indexText += ':computer: *NASDAQ:* ' + (indices.nasdaq.value || 'N/A') + ' (' + (indices.nasdaq.percentChange || 'N/A') + ')\n';
if (indices.dowJones) indexText += ':classical_building: *Dow Jones:* ' + (indices.dowJones.value || 'N/A') + ' (' + (indices.dowJones.percentChange || 'N/A') + ')\n';
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: indexText } });
blocks.push({ type: 'divider' });

const gainers = ai.topGainers || [];
const losers = ai.topLosers || [];
let moversText = '';
if (gainers.length > 0) {
  moversText += ':arrow_up: *Top Gainers:*\n';
  gainers.slice(0, 5).forEach(g => { moversText += '  ' + g.name + ' ' + g.change + '\n'; });
}
if (losers.length > 0) {
  moversText += ':arrow_down: *Top Losers:*\n';
  losers.slice(0, 5).forEach(l => { moversText += '  ' + l.name + ' ' + l.change + '\n'; });
}
if (moversText) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: moversText.slice(0, 2900) } });
  blocks.push({ type: 'divider' });
}

const sectors = ai.sectorPerformance || [];
if (sectors.length > 0) {
  let sectorText = '*Sector Performance:*\n';
  sectors.slice(0, 6).forEach(s => {
    sectorText += ':small_blue_diamond: *' + s.sector + ':* ' + s.performance + ' - _' + (s.outlook || '') + '_\n';
  });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: sectorText.slice(0, 2900) } });
  blocks.push({ type: 'divider' });
}

const catalysts = ai.keyCatalysts || [];
if (catalysts.length > 0) {
  let catText = '*Key Catalysts:*\n';
  catalysts.slice(0, 5).forEach((c, i) => { catText += (i + 1) + '. ' + c + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: catText } });
}

if (ai.tradingOutlook) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: ':crystal_ball: *Outlook:* ' + ai.tradingOutlook } });
}

blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Powered by Exa + Claude AI | One CLI' }] });

const fallback = 'Market Summary ' + date + ': Sentiment ' + (ai.marketSentiment || 'unknown');
return { blocks, fallback };
